import{c as a,Q as i,j as p,m as t}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"致皮斯托亚的专员","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/14-致皮斯托亚的专员.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/14-致皮斯托亚的专员.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/14-致皮斯托亚的专员.md"};function c(l,e,o,_,s,m){return i(),p("div",null,[...e[0]||(e[0]=[t('<h1 id="致皮斯托亚的专员" tabindex="-1">致皮斯托亚的专员 <a class="header-anchor" href="#致皮斯托亚的专员" aria-label="Permalink to &quot;致皮斯托亚的专员&quot;">​</a></h1><p>致皮斯托亚的专员 1501年10月26日</p><p>按照尼科洛 · 马基雅维利今天上午观察到的，这里的情势的重中之重 在于使那些居住在城内和乡村的居民恢复秩序。因为按照他的报告，你们 应当重视让乡村地区的居民首先服从秩序，目前当务之急是要和平谈判， 按照协议条款的精神，归还上述两派居民非法占有的农庄和粮食以及其他</p><p>①英译本和贝尔泰利编校本均未收入，依据1843年意大利文版《马基雅维利全集》译出。 ——中译者注</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>任何东西，并按照互不干涉的原则生活，如同你们曾经看到的某种迹象一 样，他们都不愿意让任何合法的房主进入自己家中；这种事情对我们而言 似乎是相当严重的，并会引发新的骚乱，你们曾设想在上述那些反叛严重 的居民中驻扎100名兵士，我们认为这非常切中要害。然而，目前时机尚 不成熟，无法动用此类手段，只能借助于其他手段，例如设想是否可以用 某种冠冕堂皇的借口夺取比萨的领土，或者如果能够在七八天时间将弗朗 切斯科的200人从平原调来，以及将德拉古乔手下差不多一样多的人马从 城里调来，诸位大人就可以采取你们认为合宜的某种新的计谋。通过这种 方式，将他们的精力从这场内部战事中转移开来，并一点一滴地确保其发 挥效用，以致我们可以对他们进行引导。我们将这一切都交给诸位大人的 睿智和明断，采取你们认为合适的方式，实施你们认为必要的计划；而 且，每一次计划的实施都恳切诸位大人让我们知晓，我们会尽全力效劳， 并尽力为你们实施的计划辩护。如果诸位大人觉得要如此调动他们，无论 是弗朗切斯科还是德拉古乔，就要领导他们， 一支部队配备骑兵，另一支 为步兵，我们也会听任你们的调遣，因为我们希望为了荣誉而执行你们有 关此事下令执行的任何任务。 然而，这个计划实施起来绝非易事，我们认为唯一有效的解决之道是 彻底重组这个城市；让潘恰蒂奇家族的人尽可能多地回来；设置所有的官 职，并将所有其他必不可少的事务安排妥当，使他们的归来成为现实；为 达此目的，我们现在不必操心乡村地区的具体事务，对于在此事上拿城邦 的声誉试运气，你们也表现怀疑，而是要安慰所有要求离开的人；并投入 全力处理该城的内部事务，因为只要我们不断地努力工作，潘恰蒂奇家族 的人就会大量地回来；完全按照条约的规定，填补职位空缺，我们认为乡 村地区的管理并非难事，因为一些城市居民和修道院长愿意提供帮助，我 们已在附件中致信他们，使用我们觉得最为得体的言辞，安排他们工作， 使这些事情有条不紊地进行。 然而，我们听说发生了两件事，搅乱了全部谈判，或者你们正在进行</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>的谈判。第一件事是潘恰蒂奇家族中一个名叫内利的人就在你们手里，潘 恰蒂奇家族提出要此人；坎切列里家族这边也提出要一个人，此人于好几 个月前被佩乔内俘获，交给了比萨。第二件事有关一栋位于圣保罗区的房 屋，德拉古乔声称对其拥有产权，而帕拉米德斯则要求他归还。在内利被 关押期间，首先通过你们的信件，然后通过尼科洛 · 马基雅维利，他了解 到事情的经过，我们只是陷入窘境之中，菲利波和安东尼二位大人曾经承 诺将他从坎切列里家族手里解救出来，他们没有把他交到潘恰蒂奇家族手 里，后来，他的确被交出去了，却是在比萨人手里；因为这个承诺确实是 你们做出的，我们看不出潘恰蒂奇家族为什么没有要回他们的人的原因； 然而，我们还是想为你们的荣誉效劳，而另一方面，还是想移开这块丑闻 的石头，我们希望知道从什么地方能够支付那笔赎金，从比萨方面将此人 赎回来，我们预计其数额不超过50达克特；如果能够从全体潘恰蒂奇家族 中筹集到这笔钱，将是我们所乐意的，而我们相信这对你们而言不在话 下，这样一来，他们的首领会倾向于你们，尤其是那些更加期望和平的 人，向他们表明你们不希望如此微不足道的小事会使得和平毁于一旦。然 而，如果你们无法做到这样，我们会写信通知你们，找到某种途径得到这 50达克特，这也是我们应该承担的某种责任，我们总是赞成这么做；因为 直至今日，我们已经花费甚多，不情愿被这样一件微不足道的小事干扰， 或者因此节外生枝；然而， 一切都由诸位大人定夺，并通知我们。关于那 栋房屋的问题，如果你们能够按照条约的规定将它让渡给潘恰蒂奇家族的 人，而不引起上述骚乱的话，我们则乐见其成；如果不是这样的话，我们 则希望你们无论如何将上述房屋转让给帕拉米德斯，使得此转让的有效期 是三四个月，并向德拉古乔保证绝不违反他对它的所有权，也不会违反条 约的规定；也应该让他相信此事，因为我们不愿意这件事阻止潘恰蒂奇家 族的回归，我们将这个事件的解决建立在他们的回归之上。 我们不希望你们忘记主教的回归，我们只是通过尼科洛 · 马基雅维利 才知道他的归来；因为我们关于他回来的事情给他写了2封信，随信一起</p><p>Opere complete di Niccolo Machiavelli</p><p>寄出：一封信是鼓励他回来，另一封信则是命令他回来；那封鼓励他的信 是以这种样式的十字架为标志，另一封命令他的信则没有任何标志。然 而，我们希望马上就能给他看那封鼓励他来的信；如果1小时内他还没有 上马启程，你们就交给他那封命令的信，我们相信他会服从的。 我们再没有什么好回复从尼科洛那里写给我们的报告了。我们想要催 促诸位大人不要忘记你们各自的责任；因为尼科洛告诉过我们，你们曾经 提到，你们当中的一位会每日都会带着那些兵士出外巡视，并对任何不利 事件采取必要措施，惩处任何作奸犯科而又罪有应得之人，同时，在邦中 维持法度之荣誉，一旦这一计划能够付诸实施，我们一定会欢欣鼓舞，因 为我们认为它是非常行之有效的；所以，我们非常鼓励你们这么做，尤其 是你们在此类事情上更加积极主动，我们在此事上看到的只有荣耀。由于 你们在最近的信件中告诉我们，同那些高级神职人员有关蒙太古领主以及 科尔索大使的报酬问题的谈判进行得相当困难，我们不愿意违反对他们两 人的承诺，不得不先借债支付他们；在我们支出之前，我们会设法这么 做，甚至我们会千方百计地做到。再会!</p><p>信件2</p>',11)])])}const h=a(r,[["render",c]]);export{d as __pageData,h as default};
